text = raw

targets = [
("يَمْحُو اللَّهُ مَا يَشَاءُ وَيُثْبِتُ وَعِنْدَهُ أُمُّ الْكِتَابِ", "Aya"),
("وَأَنْفِقُوا فِي سَبِيلِ اللَّهِ وَلَا تُلْقُوا بِأَيْدِيكُمْ إِلَى التَّهْلُكَةِ وَأَحْسِنُوا إِنَّ اللَّهَ يُحِبُّ الْمُحْسِنِينَ", "Aya"),
("ما نقصت صدقة من مال", "Hadith"),
("ثلاثة لا ينالهم الله بشفاعتي يوم القيامة: مدمن خمر، وعاق، ومن زعم أنه لا حاجة له في النساء", "Hadith"),
("ما من يوم يصبح العباد فيه إلا ملكان ينزلان، فيقول أحدهما: اللهم أعط منفقا خلفا، ويقول الآخر: اللهم أعط ممسكا تلفا", "Hadith"),
]
occurrences = []
for span_text, typ in targets:
    start = text.find(span_text)
    if start == -1:
        print("Not found:", span_text)
    else:
        # find all occurrences
        i = 0
        while True:
            idx = text.find(span_text, i)
            if idx == -1:
                break
            end = idx + len(span_text)
            occurrences.append((idx, end, span_text, typ))
            i = end  # search after end to avoid overlapping duplicates within same occurrence
for o in sorted(occurrences, key=lambda x: (x[0], x[1])):
    print(o)
len(occurrences)
